using (enumerator)
        {
            while (true)
            {
                bool moved;
                try
                {
                    cancellationToken.ThrowIfCancellationRequested();
                    moved = enumerator.MoveNext();
                }
                catch (Exception ex) when (ex is IOException or UnauthorizedAccessException or System.Security.SecurityException)
                {
                    logger.LogDebug(ex, "Discovery: failed to enumerate {EntryKind} under '{Root}'.", entryKind, root);
                    yield break;
                }

                if (!moved)
                {
                    yield break;
                }

                yield return enumerator.Current;
            }
        }

foreach (var tag in GetGitHubTagCandidates(version))
        {
            var releaseUrl = $"{GitHubApiBaseUrl}/repos/{GitHubRepository}/releases/tags/{Uri.EscapeDataString(tag)}";
            using var request = CreateGitHubRequest(releaseUrl);
            using var response = await httpClient.SendAsync(request, cancellationToken).ConfigureAwait(false);

            if (response.StatusCode == HttpStatusCode.NotFound)
            {
                continue;
            }

            if (!response.IsSuccessStatusCode)
            {
                logger.LogDebug("Failed to fetch Aspire skills GitHub release {Tag}: HTTP {StatusCode}.", tag, response.StatusCode);
                return null;
            }

            var json = await response.Content.ReadAsStringAsync(cancellationToken).ConfigureAwait(false);
            return ParseGitHubReleaseInfo(json);
        }

if (root.TryGetProperty("assets", out var assetsElement) && assetsElement.ValueKind == JsonValueKind.Array)
        {
            foreach (var assetElement in assetsElement.EnumerateArray())
            {
                if (!assetElement.TryGetProperty("name", out var nameElement) ||
                    nameElement.ValueKind != JsonValueKind.String ||
                    !assetElement.TryGetProperty("browser_download_url", out var downloadUrlElement) ||
                    downloadUrlElement.ValueKind != JsonValueKind.String)
                {
                    continue;
                }

                var name = nameElement.GetString();
                var downloadUrl = downloadUrlElement.GetString();
                if (!string.IsNullOrWhiteSpace(name) && !string.IsNullOrWhiteSpace(downloadUrl))
                {
                    assets.Add(new GitHubReleaseAsset(name, downloadUrl));
                }
            }
        }

foreach (var directory in Directory.GetDirectories(cacheRoot))
        {
            try
            {
                var name = Path.GetFileName(directory);
                if (name.StartsWith(".", StringComparison.Ordinal) || string.Equals(name, currentVersion, StringComparison.Ordinal))
                {
                    continue;
                }

                var lastUsed = GetLastUsed(directory);
                if (now - lastUsed <= maxAge)
                {
                    continue;
                }

                TryDeleteDirectory(directory);
            }
            catch (Exception ex) when (ex is IOException or UnauthorizedAccessException)
            {
                logger.LogDebug(ex, "Failed to evaluate Aspire skills cache directory {Directory} for cleanup.", directory);
            }
        }

foreach (var entry in archive.Entries)
        {
            if (string.IsNullOrWhiteSpace(entry.FullName))
            {
                continue;
            }

            var destinationPath = GetSafeArchiveDestinationPath(destinationRoot, entry.FullName);
            if (entry.FullName.EndsWith("/", StringComparison.Ordinal) || entry.FullName.EndsWith("\\", StringComparison.Ordinal))
            {
                Directory.CreateDirectory(destinationPath);
                continue;
            }

            var destinationFileDirectory = Path.GetDirectoryName(destinationPath);
            if (!string.IsNullOrEmpty(destinationFileDirectory))
            {
                Directory.CreateDirectory(destinationFileDirectory);
            }

            entry.ExtractToFile(destinationPath, overwrite: false);
        }

try
        {
            var content = File.ReadAllText(configFilePath);

            // Remove single-line comments for parsing (JSONC support)
            content = RemoveJsonComments(content);

            var config = JsonNode.Parse(content)?.AsObject();

            if (config is null)
            {
                return false;
            }

            if (config.TryGetPropertyValue("mcp", out var mcpNode) && mcpNode is JsonObject mcp)
            {
                return mcp.ContainsKey(AspireServerName);
            }

            return false;
        }
        catch (JsonException)
        {
            // If the JSON is malformed, assume aspire is not configured
            return false;
        }

foreach (var skillBaseDir in selectedSkillDirectories)
        {
            if (string.Equals(skillBaseDir, s_primarySkillBaseDirectory, StringComparison.OrdinalIgnoreCase))
            {
                continue;
            }

            var targetSkillDir = Path.Combine(repoRoot, skillBaseDir, PlaywrightCliSkillName);

            try
            {
                SyncDirectory(primarySkillDir, targetSkillDir);
                logger.LogDebug("Mirrored playwright-cli skills to {TargetDir}.", targetSkillDir);
            }
            catch (Exception ex) when (ex is IOException or UnauthorizedAccessException)
            {
                logger.LogWarning(ex, "Failed to mirror playwright-cli skills to {TargetDir}.", targetSkillDir);
            }
        }

if (Directory.Exists(targetDir))
        {
            foreach (var targetFile in Directory.GetFiles(targetDir, "*", SearchOption.AllDirectories))
            {
                var relativePath = Path.GetRelativePath(targetDir, targetFile);
                var sourceFile = Path.Combine(sourceDir, relativePath);

                if (!File.Exists(sourceFile))
                {
                    File.Delete(targetFile);
                }
            }

            // Remove empty directories in target
            foreach (var dir in Directory.GetDirectories(targetDir, "*", SearchOption.AllDirectories)
                .OrderByDescending(d => d.Length))
            {
                if (Directory.Exists(dir) && Directory.GetFileSystemEntries(dir).Length == 0)
                {
                    Directory.Delete(dir);
                }
            }
        }

try
        {
            var response = await rpc.InvokeWithProfilingAsync<GetCapabilitiesResponse?>(
                profilingTelemetry,
                "auxiliary",
                "GetCapabilitiesAsync",
                [new GetCapabilitiesRequest()],
                cancellationToken).ConfigureAwait(false);
            var capabilities = response?.Capabilities;
            logger.LogDebug("AppHost capabilities: {Capabilities}", capabilities is not null ? string.Join(", ", capabilities) : "null");
            return capabilities;
        }
        catch (RemoteMethodNotFoundException)
        {
            // Older AppHost without GetCapabilitiesAsync - assume v1 only
            logger.LogDebug("AppHost does not support GetCapabilitiesAsync, assuming v1 only");
            return null;
        }
        catch (Exception ex)
        {
            // Log any other exception
            logger.LogWarning(ex, "Failed to fetch capabilities from AppHost");
            return null;
        }

try
        {
            var snapshots = await rpc.InvokeWithProfilingAsync<List<ResourceSnapshot>>(
                _profilingTelemetry,
                "auxiliary",
                "GetResourceSnapshotsAsync",
                [],
                cancellationToken).ConfigureAwait(false) ?? [];

            if (!includeHidden)
            {
                snapshots = snapshots.Where(s => !ResourceSnapshotMapper.IsHiddenResource(s)).ToList();
            }

            // Sort resources by name for consistent ordering.
            return snapshots.OrderBy(s => s.Name, StringComparer.OrdinalIgnoreCase).ToList();
        }
        catch (RemoteMethodNotFoundException ex)
        {
            _logger.LogDebug(ex, "GetResourceSnapshotsAsync RPC method not available on the remote AppHost. The AppHost may be running an older version.");
            return [];
        }

if (!SupportsV2)
        {
            // Fall back to v1 and convert
            var legacyInfo = await GetAppHostInformationAsync(cancellationToken).ConfigureAwait(false);
            if (legacyInfo is null)
            {
                return null;
            }

            return new GetAppHostInfoResponse
            {
                Pid = legacyInfo.ProcessId.ToString(System.Globalization.CultureInfo.InvariantCulture),
                AspireHostVersion = "unknown",
                AppHostPath = legacyInfo.AppHostPath,
                CliProcessId = legacyInfo.CliProcessId,
                StartedAt = legacyInfo.StartedAt,
                CliLogFilePath = legacyInfo.CliLogFilePath
            };
        }

if (!SupportsV2)
        {
            // Fall back to v1 - convert request arguments
            Dictionary<string, JsonElement>? arguments = null;
            if (request.Arguments is JsonElement argsElement && argsElement.ValueKind == JsonValueKind.Object)
            {
                arguments = new Dictionary<string, JsonElement>();
                foreach (var prop in argsElement.EnumerateObject())
                {
                    arguments[prop.Name] = prop.Value;
                }
            }

            var result = await CallResourceMcpToolAsync(request.ResourceName, request.ToolName, arguments, cancellationToken).ConfigureAwait(false);

            return new CallMcpToolResponse
            {
                IsError = result.IsError ?? false,
                Content = result.Content.Select(c => new McpToolContentItem
                {
                    Type = c.Type,
                    Text = (c as ModelContextProtocol.Protocol.TextContentBlock)?.Text
                }).ToArray()
            };
        }

while (!_cancellationToken.IsCancellationRequested)
        {
            try
            {
                await ConnectAsync(_socketPath, _autoReconnect, retryCount, _cancellationToken).ConfigureAwait(false);
                logger.LogInformation("Successfully reconnected to backchannel");
                return;
            }
            catch (SocketException) when (DateTime.UtcNow - startTime < maxWait)
            {
                retryCount++;
                // Socket not ready yet, wait and retry
                await Task.Delay(500, _cancellationToken).ConfigureAwait(false);
            }
            catch (SocketException)
            {
                // Timeout exceeded — fall through to warning
                break;
            }
        }

if (!string.IsNullOrEmpty(selectedPath))
        {
            var selectedConnection = connections.FirstOrDefault(c =>
                c.AppHostInfo?.AppHostPath != null &&
                string.Equals(c.AppHostInfo.AppHostPath, selectedPath, StringComparison.OrdinalIgnoreCase));

            if (selectedConnection != null)
            {
                logger.LogDebug("Using explicitly selected AppHost: {AppHostPath}", selectedPath);
                return selectedConnection;
            }

            logger.LogWarning("Selected AppHost at '{SelectedPath}' is no longer running, falling back to selection logic", selectedPath);
            // Clear the selection since the AppHost is no longer available
            auxiliaryBackchannelMonitor.SelectedAppHostPath = null;
        }

if (inScopeConnections.Count == 1)
        {
            // Only one in-scope AppHost, use it
            selectedConnection = inScopeConnections[0];
        }
        else if (inScopeConnections.Count > 1)
        {
            selectedConnection = await PromptForAppHostSelectionAsync(
                inScopeConnections,
                SharedCommandStrings.MultipleInScopeAppHosts,
                selectPrompt,
                path => Path.GetRelativePath(workingDirectory, path),
                cancellationToken);
        }
        else if (outOfScopeConnections.Count > 0)
        {
            selectedConnection = await PromptForAppHostSelectionAsync(
                outOfScopeConnections,
                SharedCommandStrings.NoInScopeAppHostsShowingAll,
                selectPrompt,
                path => path,
                cancellationToken);
        }

if (pid is { } pidValue && !AppHostHelper.ProcessExists(pidValue))
        {
            logger.LogDebug("Socket is orphaned (PID {Pid} not running), skipping: {SocketPath}", pidValue, socketPath);
            // Clean up the orphaned socket with double-check to minimize TOCTOU race window
            // (A new process could theoretically start with the same PID between our checks)
            try
            {
                if (!AppHostHelper.ProcessExists(pidValue))
                {
                    File.Delete(socketPath);
                    logger.LogDebug("Deleted orphaned socket: {SocketPath}", socketPath);
                }
            }
            catch (Exception ex)
            {
                logger.LogDebug(ex, "Failed to delete orphaned socket: {SocketPath}", socketPath);
            }
            failedSockets.Add(socketPath);
            return;
        }

while (!cancellationToken.IsCancellationRequested)
        {
            var changeToken = fileProvider.Watch(watchPattern);
            var tcs = new TaskCompletionSource<bool>(TaskCreationOptions.RunContinuationsAsynchronously);

            using var registration = changeToken.RegisterChangeCallback(state => ((TaskCompletionSource<bool>)state!).TrySetResult(true), tcs);
            using var cancellationRegistration = cancellationToken.Register(() => tcs.TrySetCanceled());

            bool changed;
            try
            {
                changed = await tcs.Task.ConfigureAwait(false);
            }
            catch (TaskCanceledException)
            {
                yield break;
            }

            yield return changed;
        }

try
        {
            // Re-check after acquiring lock — another process may have already extracted
            if (!force && layoutDiscovery.DiscoverLayout() is not null)
            {
                var existingVersion = ReadVersionMarker(destinationPath);
                var currentVersion = GetCurrentVersion(ProcessPathOverride);
                if (existingVersion == currentVersion)
                {
                    logger.LogDebug("Bundle already extracted and up to date (version: {Version}).", existingVersion);
                    return BundleExtractResult.AlreadyUpToDate;
                }

                logger.LogDebug("Version mismatch: existing={ExistingVersion}, current={CurrentVersion}. Re-extracting.", existingVersion, currentVersion);
            }

            return await ExtractCoreAsync(destinationPath, cancellationToken);
        }
        catch (Exception ex)
        {
            logger.LogError(ex, "Failed to extract bundle to {Path}", destinationPath);
            return BundleExtractResult.ExtractionFailed;
        }

try
        {
            file.Delete();
            if (expired)
            {
                _logger.LogTrace("Deleted expired cache file: {CacheFile}", file.FullName);
            }
            else if (old)
            {
                _logger.LogTrace("Deleted old cache file during global cleanup: {CacheFile}", file.FullName);
            }
            else if (invalid)
            {
                _logger.LogTrace("Deleted invalid cache file: {CacheFile}", file.FullName);
            }
            else
            {
                _logger.LogTrace("Deleted cache file: {CacheFile}", file.FullName);
            }
        }
        catch (Exception ex)
        {
            _logger.LogDebug(ex, "Failed to delete cache file {CacheFile}", file.FullName);
        }

if (includePrivateKey && format == CertificateKeyExportFormat.Pem)
        {
            Debug.Assert(pemEnvelope != null);

            try
            {
                var keyPath = Path.ChangeExtension(path, ".key");
                Log.WritePemKeyToDisk(keyPath);

                // Create a temp file with the correct Unix file mode before moving it to the expected path.
                if (!RuntimeInformation.IsOSPlatform(OSPlatform.Windows))
                {
                    var tempFilename = Path.GetTempFileName();
                    File.Move(tempFilename, keyPath, overwrite: true);
                }

                File.WriteAllBytes(keyPath, pemEnvelope);
            }
            catch (Exception ex)
            {
                Log.WritePemKeyToDiskError(ex.ToString());
                throw;
            }
            finally
            {
                Array.Clear(pemEnvelope, 0, pemEnvelope.Length);
            }
        }

try
        {
            if (Log.IsEnabled())
            {
                Log.MacOSAddCertificateToUserProfileDirStart(s_macOSUserKeychain, GetDescription(certificate));
            }

            ExportCertificate(certificate, GetCertificateFilePath(certificate), includePrivateKey: true, null, CertificateKeyExportFormat.Pfx);

            var aspireLookup = GetAspireCertificateHash(certificate);
            ExportCertificate(certificate, Path.Combine(s_aspireDevCertsCacheDirectory, $"{aspireLookup}.pfx"), includePrivateKey: true, null, CertificateKeyExportFormat.Pfx);
        }
        catch (Exception ex)
        {
            Log.MacOSAddCertificateToUserProfileDirError(certificate.Thumbprint, ex.Message);
        }

if (!Directory.Exists(s_macOSUserHttpsCertificateLocation))
        {
            Log.MacOSDiskStoreDoesNotExist();
        }
        else
        {
            var certificateFiles = Directory.EnumerateFiles(s_macOSUserHttpsCertificateLocation, "aspnetcore-localhost-*.pfx");
            foreach (var file in certificateFiles)
            {
                try
                {
                    var certificate = X509CertificateLoader.LoadPkcs12FromFile(file, password: null);
                    certsFromDisk.Add(certificate);
                }
                catch (Exception)
                {
                    Log.MacOSFileIsNotAValidCertificate(file);
                    throw;
                }
            }
        }

if (nssDbs.Count > 0)
        {
            var isCertUtilAvailable = IsCommandAvailable(CertUtilCommand);
            if (!isCertUtilAvailable)
            {
                Log.UnixMissingCertUtilCommand(CertUtilCommand);
                // We'll loop over the nssdbs anyway so they'll be listed
            }

            foreach (var nssDb in nssDbs)
            {
                if (isCertUtilAvailable && TryRemoveCertificateFromNssDb(nickname, nssDb))
                {
                    Log.UnixNssDbUntrustSucceeded(nssDb.Path);
                }
                else
                {
                    Log.UnixNssDbUntrustFailed(nssDb.Path);
                    sawUntrustFailure = true;
                }
            }
        }

try
        {
            // c_rehash actually does this twice: once with -subject_hash (equivalent to -hash) and again
            // with -subject_hash_old.  Old hashes are only  needed for pre-1.0.0, so we skip that.
            var processInfo = new ProcessStartInfo(OpenSslCommand, $"x509 -hash -noout -in {certificatePath}")
            {
                RedirectStandardOutput = true,
                RedirectStandardError = true
            };

            using var process = Process.Start(processInfo);
            var stdout = process!.StandardOutput.ReadToEnd();

            process.WaitForExit();
            if (process.ExitCode != 0)
            {
                Log.UnixOpenSslHashFailed(certificatePath);
                return false;
            }

            hash = stdout.Trim();
            return true;
        }
        catch (Exception ex)
        {
            Log.UnixOpenSslHashException(certificatePath, ex.Message);
            return false;
        }

if (!string.IsNullOrEmpty(currentSslCertDir))
        {
            var paths = currentSslCertDir.Split(Path.PathSeparator, StringSplitOptions.RemoveEmptyEntries);
            if (paths.Any(p => string.Equals(p.TrimEnd(Path.DirectorySeparatorChar), devCertsTrustPath.TrimEnd(Path.DirectorySeparatorChar), StringComparison.OrdinalIgnoreCase)))
            {
                // Already included, nothing to do
                return;
            }

            // Append the dev-certs trust path to the existing value
            environmentVariables[SslCertDirEnvVar] = $"{currentSslCertDir}{Path.PathSeparator}{devCertsTrustPath}";
        }
        else
        {
            // Set the dev-certs trust path combined with the system certificate directory.
            var systemCertDirs = CertificateHelpers.GetSystemCertificateDirectories();
            systemCertDirs.Add(devCertsTrustPath);

            environmentVariables[SslCertDirEnvVar] = string.Join(Path.PathSeparator, systemCertDirs);
        }

if (format == OutputFormat.Json)
        {
            var jsonResult = new DetachOutputInfo(
                effectiveAppHostFile.FullName,
                pid,
                result.ChildProcess!.Id,
                dashboardUrls?.BaseUrlWithLoginToken,
                childLogFile);
            var json = JsonSerializer.Serialize(jsonResult, RunCommandJsonContext.RelaxedEscaping.DetachOutputInfo);
            interactionService.DisplayRawText(json, ConsoleOutput.Standard);
        }
        else
        {
            var appHostRelativePath = Path.GetRelativePath(executionContext.WorkingDirectory.FullName, effectiveAppHostFile.FullName);
            RunCommand.RenderAppHostSummary(
                interactionService,
                appHostRelativePath,
                dashboardUrls?.BaseUrlWithLoginToken,
                codespacesUrl: null,
                childLogFile,
                isExtensionHost,
                pid);
            interactionService.DisplayEmptyLine();

            interactionService.DisplaySuccess(RunCommandStrings.AppHostStartedSuccessfully);
        }

try
            {
                await ConfigurationService.SetConfigurationAsync(key, value, isGlobal, cancellationToken);
                InteractionService.DisplaySuccess(isGlobal
                    ? string.Format(CultureInfo.CurrentCulture, ConfigCommandStrings.ConfigurationKeySetGlobally, key,
                        value)
                    : string.Format(CultureInfo.CurrentCulture, ConfigCommandStrings.ConfigurationKeySetLocally, key,
                        value));

                return CliExitCodes.Success;
            }
            catch (Exception ex)
            {
                var errorMessage = string.Format(CultureInfo.CurrentCulture, ErrorStrings.ErrorSettingConfiguration, ex.Message);
                Telemetry.RecordError(errorMessage, ex);
                InteractionService.DisplayError(errorMessage);
                return CliExitCodes.InvalidCommand;
            }

if (format is OutputFormat.Json)
        {
            var json = JsonSerializer.Serialize(docs.ToArray(), JsonSourceGenerationContext.RelaxedEscaping.DocsListItemArray);
            // Structured output always goes to stdout.
            InteractionService.DisplayRawText(json, ConsoleOutput.Standard);
        }
        else
        {
            InteractionService.DisplaySuccess(string.Format(CultureInfo.CurrentCulture, DocsCommandStrings.FoundDocumentationPages, docs.Count));

            var table = new Table();
            table.AddBoldColumn(DocsCommandStrings.HeaderTitle);
            table.AddBoldColumn(DocsCommandStrings.HeaderSlug);
            table.AddBoldColumn(DocsCommandStrings.HeaderSummary);

            foreach (var doc in docs)
            {
                table.AddRow(
                    Markup.Escape(doc.Title),
                    Markup.Escape(doc.Slug),
                    Markup.Escape(doc.Summary ?? "-"));
            }

            InteractionService.DisplayRenderable(table);
        }

if (isDashboardAvailable && hasTelemetryData)
        {
            // Export structured logs from Dashboard API
            await InteractionService.ShowStatusAsync(ExportCommandStrings.GatheringStructuredLogs, async () =>
            {
                await AddStructuredLogsAsync(exportArchive, client!, baseUrl!, resolvedTelemetryResources, allOtlpResources, cancellationToken).ConfigureAwait(false);
                return true;
            });

            // Export traces from Dashboard API
            await InteractionService.ShowStatusAsync(ExportCommandStrings.GatheringTraces, async () =>
            {
                await AddTracesAsync(exportArchive, client!, baseUrl!, resolvedTelemetryResources, allOtlpResources, cancellationToken).ConfigureAwait(false);
                return true;
            });
        }

try
            {
                var result = await _projectLocator.UseOrFindAppHostProjectFileAsync(null, MultipleAppHostProjectsFoundBehavior.None, createSettingsFile: false, cancellationToken);

                var json = JsonSerializer.Serialize(new AppHostProjectSearchResultPoco
                {
                    SelectedProjectFile = result.SelectedProjectFile?.FullName,
                    AllProjectFileCandidates = result.AllProjectFileCandidates.Select(f => f.FullName).ToList()
                }, BackchannelJsonSerializerContext.Default.AppHostProjectSearchResultPoco);
                // Structured output always goes to stdout.
                InteractionService.DisplayRawText(json, ConsoleOutput.Standard);
                return CommandResult.Success();
            }
            catch
            {
                return CommandResult.Failure(CliExitCodes.FailedToFindProject);
            }
